#include <stdio.h>

int main() {
    int T;
    if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int X;
        scanf("%d", &X);
        int discount = 0;
        if (X > 100 && X <= 1000) discount = 25;
        else if (X > 1000 && X <= 5000) discount = 100;
        else if (X > 5000) discount = 500;
        printf("%d\n", X - discount);
    }
    return 0;
}

