#!/usr/bin/env python3
import sys

def main():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    t = int(data[0])
    out = []
    idx = 1
    for _ in range(t):
        x = int(data[idx]); idx += 1
        if x > 100 and x <= 1000:
            discount = 25
        elif x > 1000 and x <= 5000:
            discount = 100
        elif x > 5000:
            discount = 500
        else:
            discount = 0
        out.append(str(x - discount))
    sys.stdout.write('\n'.join(out))

if __name__ == "__main__":
    main()

